SELECT COUNT(*)
FROM ADAPTER_CHANGE_LOG
WHERE PROJECT_ID = #{projectId}

SELECT COUNT(*)
FROM RELEASE_UNIT_REGISTRY
WHERE PROJECT_ID = #{projectId}

SELECT COUNT(*)
FROM ARTIFACT_LOCK
WHERE PROJECT_ID = #{projectId}

SELECT COUNT(*)
FROM PROJECT_COMPATIBILITY_RUN
WHERE PROJECT_ID = #{projectId}

mapper.update:
UPDATE PROJECT_ARTIFACT_INSTALL
SET ACTIVE_YN = 'N'
WHERE PROJECT_ID = #{projectId}
  AND ACTIVE_YN = 'Y'
  AND ARTIFACT_VERSION_ID IN (
      SELECT ARTIFACT_VERSION_ID
      FROM ARTIFACT_VERSION_REGISTRY
      WHERE ARTIFACT_ID = #{artifactId}
  )

mapper.delete:
DELETE FROM ARTIFACT_LOCK
WHERE PROJECT_ID = #{projectId}
  AND RELEASE_UNIT_ID = #{releaseUnitId}
  AND GROUP_ID = #{groupId}
  AND ARTIFACT_ID = #{artifactId}

mapper.update:
UPDATE PROJECT_DEPLOYMENT_HISTORY
STATUS = #{status}, SERVER_TARGET = #{serverTarget}, RELEASE_UNIT_ID = #{releaseUnitId}, DEPLOY_TRACE_ID = #{deployTraceId}, GIT_COMMIT_SHA = #{gitCommitSha}, RESULT_MESSAGE = #{resultMessage}, UPDATED_AT = CURRENT_DATETIME, FINISHED_AT = CURRENT_DATETIME,
WHERE DEPLOYMENT_HISTORY_ID = #{deploymentHistoryId}
